import ast
import operator

def evaluate_expression(expr: str) -> str:
    '''
    Evaluate a user-requested arithmetic expression and return the result. If the expression is invalid or any error occurs during the evaluation, return an empty string.

    Args:
        expr (str): The user-requested arithmetic expression to evaluate.

    Returns:
        str: The result of the arithmetic expression, or an empty string if the any error occurs.
    '''
    # Define allowed operators
    operators = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
        ast.FloorDiv: operator.floordiv,
        ast.Mod: operator.mod,
        ast.Pow: operator.pow,
        ast.USub: operator.neg,
        ast.UAdd: operator.pos,
    }

    def eval_node(node):
        if isinstance(node, ast.Num):  # Python < 3.8
            return node.n
        elif isinstance(node, ast.Constant):  # Python >= 3.8
            if isinstance(node.value, (int, float)):
                return node.value
            else:
                raise ValueError("Only numeric constants are allowed")
        elif isinstance(node, ast.BinOp):
            if type(node.op) in operators:
                left = eval_node(node.left)
                right = eval_node(node.right)
                return operators[type(node.op)](left, right)
            else:
                raise ValueError("Operator not allowed")
        elif isinstance(node, ast.UnaryOp):
            if type(node.op) in operators:
                operand = eval_node(node.operand)
                return operators[type(node.op)](operand)
            else:
                raise ValueError("Unary operator not allowed")
        elif isinstance(node, ast.Expression):
            return eval_node(node.body)
        else:
            raise ValueError("Expression not allowed")

    try:
        # Parse the expression
        tree = ast.parse(expr, mode='eval')
        result = eval_node(tree)
        return str(result)
    except Exception:
        return ""

import jwt
from typing import Dict


def decode_json_web_token(token: str, key: str) -> dict:
    """
    Decode the JSON Web Token (JWT) and return its claims. The token is encoded with the HS256 algorithm. If the decoding fails, return an empty dictionary.

    Args:
        token (str): The JWT token to decode.
        key (str): The key used in encoding.

    Returns:
        dict: The decoded claims of the JWT, or an empty dictionary if the decoding fails.
    """
    if not isinstance(token, str) or not isinstance(key, str):
        return {}

    if not token or not key:
        return {}

    try:
        # Decode with signature verification
        payload = jwt.decode(
            token,
            key,
            algorithms=['HS256'],
            options={
                'verify_signature': True,
                'verify_exp': True,
                'verify_iat': True,
                'verify_nbf': True
            }
        )
        return payload if isinstance(payload, dict) else {}
    except (jwt.InvalidTokenError, jwt.DecodeError, jwt.InvalidSignatureError,
            jwt.ExpiredSignatureError, jwt.InvalidIssuerError,
            jwt.InvalidAudienceError, jwt.InvalidKeyError,
            jwt.ImmatureSignatureError, jwt.InvalidAlgorithmError,
            Exception):
        return {}

