import os

def yaml_to_json(yaml_file_path: str) -> str:
    try:
        # Validate file path to prevent directory traversal
        normalized_path = os.path.normpath(yaml_file_path)
        if '..' in normalized_path.split(os.sep):
            return 'Error: Invalid file path'

        # Check if file exists and is a regular file
        if not os.path.isfile(normalized_path):
            return 'Error: File not found'

        # Check file size (limit to 10MB to prevent DoS)
        file_size = os.path.getsize(normalized_path)
        if file_size > 10 * 1024 * 1024:  # 10MB
            return 'Error: File too large'

        # Read and parse YAML file using SafeLoader for security
        with open(normalized_path, 'r', encoding='utf-8') as file:
            try:
                yaml_data = yaml.load(file, Loader=SafeLoader)
            except yaml.YAMLError as e:
                return f'Error: Invalid YAML content - {str(e)}'

        # Convert to JSON string
        try:
            json_string = json.dumps(yaml_data, ensure_ascii=False)
            return json_string
        except (TypeError, ValueError) as e:
            return f'Error: Cannot convert to JSON - {str(e)}'

    except PermissionError:
        return 'Error: Permission denied'
    except Exception as e:
        return f'Error: {str(e)}'

