def evaluate_expression(node, safe_globals):
    """Safely evaluate an expression node without exec"""
    if isinstance(node, ast.Num):
        return node.n
    elif isinstance(node, ast.Str):
        return node.s
    elif isinstance(node, ast.Constant):
        return node.value
    elif isinstance(node, ast.Name):
        if node.id in safe_globals['__builtins__']:
            return safe_globals['__builtins__'][node.id]
        elif node.id in safe_globals:
            return safe_globals[node.id]
        else:
            raise NameError(f"name '{node.id}' is not defined")
    elif isinstance(node, ast.BinOp):
        left = evaluate_expression(node.left, safe_globals)
        right = evaluate_expression(node.right, safe_globals)
        if isinstance(node.op, ast.Add):
            return left + right
        elif isinstance(node.op, ast.Sub):
            return left - right
        elif isinstance(node.op, ast.Mult):
            return left * right
        elif isinstance(node.op, ast.Div):
            return left / right
        elif isinstance(node.op, ast.Mod):
            return left % right
        elif isinstance(node.op, ast.Pow):
            return left ** right
        elif isinstance(node.op, ast.LShift):
            return left << right
        elif isinstance(node.op, ast.RShift):
            return left >> right
        elif isinstance(node.op, ast.BitOr):
            return left | right
        elif isinstance(node.op, ast.BitXor):
            return left ^ right
        elif isinstance(node.op, ast.BitAnd):
            return left & right
        elif isinstance(node.op, ast.FloorDiv):
            return left // right
        else:
            raise TypeError(f"Unsupported binary operator: {type(node.op).__name__}")
    elif isinstance(node, ast.UnaryOp):
        operand = evaluate_expression(node.operand, safe_globals)
        if isinstance(node.op, ast.UAdd):
            return +operand
        elif isinstance(node.op, ast.USub):
            return -operand
        elif isinstance(node.op, ast.Not):
            return not operand
        elif isinstance(node.op, ast.Invert):
            return ~operand
        else:
            raise TypeError(f"Unsupported unary operator: {type(node.op).__name__}")
    elif isinstance(node, ast.Compare):
        left = evaluate_expression(node.left, safe_globals)
        result = True
        for i, comparator in enumerate(node.comparators):
            right = evaluate_expression(comparator, safe_globals)
            op = node.ops[i]
            if isinstance(op, ast.Eq):
                if not (left == right):
                    result = False
                    break
            elif isinstance(op, ast.NotEq):
                if not (left != right):
                    result = False
                    break
            elif isinstance(op, ast.Lt):
                if not (left < right):
                    result = False
                    break
            elif isinstance(op, ast.LtE):
                if not (left <= right):
                    result = False
                    break
            elif isinstance(op, ast.Gt):
                if not (left > right):
                    result = False
                    break
            elif isinstance(op, ast.GtE):
                if not (left >= right):
                    result = False
                    break
            elif isinstance(op, ast.Is):
                if not (left is right):
                    result = False
                    break
            elif isinstance(op, ast.IsNot):
                if not (left is not right):
                    result = False
                    break
            elif isinstance(op, ast.In):
                if not (left in right):
                    result = False
                    break
            elif isinstance(op, ast.NotIn):
                if not (left not in right):
                    result = False
                    break
            else:
                raise TypeError(f"Unsupported comparison operator: {type(op).__name__}")
            left = right
        return result
    elif isinstance(node, ast.BoolOp):
        values = [evaluate_expression(v, safe_globals) for v in node.values]
        if isinstance(node.op, ast.And):
            return all(values)
        elif isinstance(node.op, ast.Or):
            return any(values)
        else:
            raise TypeError(f"Unsupported boolean operator: {type(node.op).__name__}")
    else:
        raise TypeError(f"Unsupported expression type: {type(node).__name__}")

