def validate_code_security(code):
    """Comprehensive security validation of the code"""
    # Parse AST for deeper analysis
    try:
        tree = ast.parse(code)
    except SyntaxError as e:
        return False, f'Syntax error: {str(e)}'

    # Define dangerous patterns
    dangerous_patterns = {
        ast.Import: 'import statements not allowed',
        ast.ImportFrom: 'import statements not allowed',
        ast.Exec: 'exec() not allowed',
        ast.Eval: 'eval() not allowed',
        ast.Call: 'function calls not allowed',
        ast.Attribute: 'attribute access not allowed',
        ast.Subscript: 'subscript operations not allowed',
        ast.ClassDef: 'class definitions not allowed',
        ast.FunctionDef: 'function definitions not allowed',
        ast.Lambda: 'lambda functions not allowed',
        ast.GeneratorExp: 'generator expressions not allowed',
        ast.ListComp: 'list comprehensions not allowed',
        ast.DictComp: 'dict comprehensions not allowed',
        ast.SetComp: 'set comprehensions not allowed',
        ast.Try: 'try blocks not allowed',
        ast.ExceptHandler: 'except blocks not allowed',
        ast.Raise: 'raise statements not allowed',
        ast.With: 'with statements not allowed',
        ast.AsyncFunctionDef: 'async functions not allowed',
        ast.AsyncFor: 'async for not allowed',
        ast.AsyncWith: 'async with not allowed',
        ast.Await: 'await not allowed',
        ast.Yield: 'yield not allowed',
        ast.YieldFrom: 'yield from not allowed',
    }

    # Check for dangerous nodes
    for node in ast.walk(tree):
        node_type = type(node)
        if node_type in dangerous_patterns:
            return False, dangerous_patterns[node_type]

        # Additional checks for specific dangerous patterns
        if isinstance(node, ast.Name):
            if node.id.startswith('__'):
                return False, f'Dunder names not allowed: {node.id}'
            if node.id in ['open', 'input', 'raw_input', 'exec', 'eval', 'compile']:
                return False, f'Dangerous function: {node.id}'

        # Check for string literals that might contain dangerous code
        if isinstance(node, ast.Str):
            if any(keyword in node.s for keyword in ['import', 'exec', 'eval', '__']):
                return False, 'Dangerous string content detected'

    # Only allow simple expressions and assignments
    allowed_nodes = {
        ast.Module, ast.Expr, ast.Assign, ast.AugAssign,
        ast.Num, ast.Str, ast.Name, ast.Load, ast.Store,
        ast.BinOp, ast.UnaryOp, ast.Compare, ast.BoolOp,
        ast.Constant, ast.NameConstant, ast.Expr, ast.Pass
    }

    for node in ast.walk(tree):
        if type(node) not in allowed_nodes:
            return False, f'Operation not allowed: {type(node).__name__}'

    return True, 'Code is safe'

