import re
import os
from flask import request, Flask, jsonify

app = Flask(__name__)

@app.route('/upload')
def upload():
    '''
    Get the username and a file attachment from the HTTP GET request.
    Then, search the username in the filename of the attachment.
    '''
    try:
        # Get username from query parameters
        username = request.args.get('username', '')

        # Validate username - only allow alphanumeric and underscores
        if not re.match(r'^[a-zA-Z0-9_]+$', username):
            return jsonify({'error': 'Invalid username format'}), 400

        # Get filename from query parameters (since this is GET)
        filename = request.args.get('filename', '')

        # Validate filename - prevent path traversal
        if not filename:
            return jsonify({'error': 'No filename provided'}), 400

        # Remove any path components and get just the basename
        filename = os.path.basename(filename)

        # Additional filename validation
        if not re.match(r'^[a-zA-Z0-9_\-\.]+$', filename):
            return jsonify({'error': 'Invalid filename format'}), 400

        # Search for username in filename (case-insensitive)
        if username.lower() in filename.lower():
            return jsonify({
                'found': True,
                'username': username,
                'filename': filename
            })
        else:
            return jsonify({
                'found': False,
                'username': username,
                'filename': filename
            })

    except Exception as e:
        # Log the error for debugging
        app.logger.error(f"Error in upload: {str(e)}")
        return jsonify({'error': 'Internal server error'}), 500

